impl HasHardwareFeatures for SimdPolicy {
    fn has_feature(&self, feat: HardwareFeature) -> bool {
        self.hardware_features.has_feature(feat) && !self.disabled_by_env.contains(&feat)
    }

    fn iter_features(&self) -> impl Iterator<Item = HardwareFeature> {
        self.hardware_features
            .set
            .difference(&self.disabled_by_env)
            .copied()
    }
}

match accept_encoding {
    // missing header; fallback to identity
    None => {
        return Either::left(CompressResponse {
            encoding: Encoding::identity(),
            fut: self.service.call(req),
            _phantom: PhantomData,
        })
    }

    // valid accept-encoding header
    Some(accept_encoding) => accept_encoding,
}

for data_len in 0..=unmasked.len() {
    let unmasked = &unmasked[0..data_len];
    // Check masking with different alignment.
    for off in 0..=3 {
        if unmasked.len() < off {
            continue;
        }
        let mut masked = unmasked.to_vec();
        apply_mask_fallback(&mut masked[off..], mask);

        let mut masked_fast = unmasked.to_vec();
        apply_mask_fast32(&mut masked_fast[off..], mask);

        assert_eq!(masked, masked_fast);
    }
}

if cmd
        .get_positionals()
        .any(|p| p.is_last_set() && p.is_required_set())
        && cmd.has_subcommands()
        && !cmd.is_subcommand_negates_reqs_set()
    {
        panic!(
            "Having a required positional argument with .last(true) set *and* child \
                 subcommands without setting SubcommandsNegateReqs isn't compatible."
        );
    }

loop {
    let now = Instant::now();

    let deadline = match deadline {
        // Check if we can receive the next message.
        _ if now >= self.delivery_time => break,
        // Check if the timeout deadline has been reached.
        Some(d) if now >= d => return Err(RecvTimeoutError::Timeout),

        // Sleep until one of the above happens
        Some(d) if d < self.delivery_time => d,
        _ => self.delivery_time,
    };

    thread::sleep(deadline - now);
}

if packet.on_stack {
    // The message has been in the packet from the beginning, so there is no need to wait
    // for it. However, after reading the message, we need to set `ready` to `true` in
    // order to signal that the packet can be destroyed.
    let msg = unsafe { packet.msg.get().replace(None).unwrap() };
    packet.ready.store(true, Ordering::Release);
    Ok(msg)
} else {
    // Wait until the message becomes available, then read it and destroy the
    // heap-allocated packet.
    packet.wait_ready();
    let msg = unsafe { packet.msg.get().replace(None).unwrap() };
    drop(unsafe { Box::from_raw(token.zero.0.cast::<Packet<T>>()) });
    Ok(msg)
}

loop {
    // Set the Entry of the to-be-inserted element to point to the previous successor of
    // `to`.
    unsafe { (*entry).next.store(next, Relaxed) }
    match to.compare_exchange_weak(next, entry_ptr, Release, Relaxed, guard) {
        Ok(_) => break,
        // We lost the race or weak CAS failed spuriously. Update the successor and try
        // again.
        Err(err) => next = err.current,
    }
}

if new_head & HAS_NEXT == 0 {
    let tail = *self.tail.index.get_mut();

    // If the tail equals the head, that means the queue is empty.
    if head >> SHIFT == tail >> SHIFT {
        return None;
    }

    // If head and tail are not in the same block, set `HAS_NEXT` in head.
    if (head >> SHIFT) / LAP != (tail >> SHIFT) / LAP {
        new_head |= HAS_NEXT;
    }
}

loop {
    let previous = self.state_lo.swap(1, Ordering::Acquire);

    if previous != 1 {
        // To synchronize with the acquire fence in `validate_read` via any modification to
        // the data at the critical section of `(state_hi, previous)`.
        atomic::fence(Ordering::Release);

        return SeqLockWriteGuard {
            lock: self,
            state_lo: previous,
        };
    }

    backoff.snooze();
}

for (index, decl) in op_method_decls.iter_mut().enumerate() {
  if let Some(mut constructor) = decl.constructor {
    constructor.name = decl.name.0;
    constructor.name_fast = decl.name.1;

    op_ctxs.push(create_ctx(index, constructor));
  }

  for method in decl.methods {
    op_ctxs.push(create_ctx(index, *method));
  }
  for method in decl.static_methods {
    op_ctxs.push(create_ctx(index, *method));
  }
}

if let Some(ignore_comment) = maybe_ignore_comment {
  new_text = format!(" {code}");
  // Get the end position of the comment.
  let index = text_info.line_and_column_index(ignore_comment.end());
  let position = lsp::Position {
    line: index.line_index as u32,
    character: index.column_index as u32,
  };
  range = lsp::Range {
    start: position,
    end: position,
  };
} else {
  new_text = format!("// deno-lint-ignore-file {code}\n");
  range = next_leading_comment_range;
}

if data_is_sorted_and_delta_encoded {
  for i in 0..token_count {
    let src_offset = 5 * i;
    result.push(SemanticToken {
      delta_line: data[src_offset],
      delta_start: data[src_offset + 1],
      length: data[src_offset + 2],
      token_type: data[src_offset + 3],
      token_modifiers_bitset: data[src_offset + 4],
    });
  }
  return result;
}

if let Some(stem) = path.strip_suffix(".tsx") {
  format!("{stem}.d.ts")
} else if let Some(stem) = path.strip_suffix(".ts") {
  format!("{stem}.d.ts")
} else if let Some(stem) = path.strip_suffix(".mts") {
  format!("{stem}.d.mts")
} else if let Some(stem) = path.strip_suffix(".cts") {
  format!("{stem}.d.cts")
} else if let Some(stem) = path.strip_suffix(".js") {
  format!("{stem}.d.ts")
} else if let Some(stem) = path.strip_suffix(".mjs") {
  format!("{stem}.d.mts")
} else {
  format!("{path}.d.ts")
}

if !pack_flags.allow_slow_types {
  let fast_check_workspace_member =
    config_to_deno_graph_workspace_member(&package.config_file)?;

  module_graph_creator
    .module_graph_builder()
    .build_fast_check_graph(
      &mut graph,
      BuildFastCheckGraphOptions {
        workspace_fast_check: WorkspaceFastCheckOption::Enabled(&[
          fast_check_workspace_member,
        ]),
        fast_check_dts: true,
      },
    )?;
}

for component in rel.components() {
  let std::path::Component::Normal(name) = component else {
    continue;
  };
  let Some(name) = name.to_str() else { continue };
  if name == ".git" || name == "node_modules" {
    return true;
  }
  // .env, .env.local, .env.production, etc.
  if name == ".env" || name.starts_with(".env.") {
    return true;
  }
}

for ts_ref in &module_info.ts_references {
  let specifier_with_range = match ts_ref {
    TypeScriptReference::Path(s) => s,
    TypeScriptReference::Types { specifier, .. } => specifier,
  };
  unfurl_specifier_with_range(
    &specifier_with_range.text,
    &specifier_with_range.range,
    text_info,
    &mut text_changes,
    &mut dependencies,
  );
}

for (pkg_name, pkg_advisories) in &bulk_response {
  for adv in pkg_advisories {
    advisories.push(AuditAdvisory {
      title: adv.title.clone(),
      severity: adv.severity.clone(),
      url: adv.url.clone(),
      module_name: pkg_name.clone(),
      vulnerable_versions: adv.vulnerable_versions.clone(),
      patched_versions: adv.patched_versions.clone().unwrap_or_default(),
      cves: adv.cves.clone(),
    });
  }
}

if let Some(outdir) = output_dir {
  let outdir = cwd.join(outdir);
  let relative = js_filename
    .strip_prefix(cwd)
    .map_err(|_| {
      anyhow::anyhow!(
        "Input file {} is not under the current directory. Use --output instead.",
        input_path.display()
      )
    })?;
  Ok(outdir.join(relative))
} else {
  // Write alongside source file
  Ok(js_filename)
}

for (is_cjs, specifier) in args.specifiers {
  let result = super::resolve_specifier_for_tsc(
    specifier,
    &referrer,
    &state.graph,
    if is_cjs {
      ResolutionMode::Require
    } else {
      ResolutionMode::Import
    },
    state.maybe_npm.as_ref(),
    referrer_module,
    &mut state.remapped_specifiers,
  )?;
  resolved.push(result);
}

if let Some(cache_id) = maybe_cache_id {
  let cache_dir = cache_storage_dir.join(cache_id.to_string());
  #[allow(
    clippy::disallowed_methods,
    reason = "cache storage manages its own directory"
  )]
  if cache_dir.exists() {
    #[allow(
      clippy::disallowed_methods,
      reason = "cache storage manages its own directory"
    )]
    std::fs::remove_dir_all(cache_dir)?;
  }
}

if self.idx < self.params.segment_count() {
    let idx = self.idx;
    let res = match self.params.segments[idx].1 {
        PathItem::Static(ref seg) => seg,
        PathItem::Segment(start, end) => {
            &self.params.path.path()[(start as usize)..(end as usize)]
        }
    };
    self.idx += 1;
    return Some((&self.params.segments[idx].0, res));
}

for pref in &self.0 {
    // only change if strictly greater
    // equal items, even while unsorted, still have higher preference if they appear first

    let rank = encoding_rank(pref);

    if (pref.quality, rank) > (max_pref, max_rank) {
        max_pref = pref.quality;
        max_item = Some(pref.item.clone());
        max_rank = rank;
    }
}

if self.print_labels {
    for config in &configs {
        let labels = vec![
            format!("reader-{}", config.label),
            format!("slice-{}", config.label),
        ];
        for label in &labels {
            if self.include(label) {
                println!("{}", label);
            } else {
                println!("{} (ignored)", label);
            }
        }
    }
}

for config in &configs {
    let label = format!("reader-{}", config.label);
    if self.include(&label) {
        let got = config.search_reader(&self.haystack);
        assert_eq_printed!(config.expected_reader, got, "{}", label);
    }

    let label = format!("slice-{}", config.label);
    if self.include(&label) {
        let got = config.search_slice(&self.haystack);
        assert_eq_printed!(config.expected_slice, got, "{}", label);
    }
}

for req in unrolled_reqs.iter().chain(incls.iter()) {
    if self.cmd.find_group(req).is_some() {
        let group_members = self.cmd.unroll_args_in_group(req);
        let elem = self.cmd.format_group(req);
        required_groups.insert(elem);
        required_groups_members.extend(group_members);
    } else {
        debug_assert!(self.cmd.find(req).is_some());
    }
}

for subcommand in cmd.get_subcommands() {
    for subcommand_name in subcommand.get_name_and_visible_aliases() {
        let mut parent_commands: Vec<_> = parent_commands.into();
        parent_commands.push(subcommand_name);
        gen_fish_inner(
            root_command,
            &parent_commands,
            subcommand,
            buffer,
            needs_fn_name,
            using_fn_name,
        );
    }
}

for extension in extensions {
  if let Some(middleware) = extension.get_global_template_middleware() {
    global_template_middlewares.push(middleware);
  }
  if let Some(middleware) = extension.get_global_object_middleware() {
    global_object_middlewares.push(middleware);
  }
  additional_references
    .extend_from_slice(extension.get_external_references());
}

if !dry_run {
  log_stats(&state, &deno_dir.root);

  if let Some(dir) = node_modules_path {
    log_stats(&node_modules_cleaned, dir);
  }
  if let Some(dir) = options.vendor_dir_path() {
    log_stats(&vendor_cleaned, dir);
  }

  let mut failed = state.failed;
  failed.extend(node_modules_cleaned.failed);
  failed.extend(vendor_cleaned.failed);
  report_locked_files(&failed);
}

if error_ref.is_module_not_found {
  Some(Self::from_missing_error(
    error_ref.specifier,
    Some(error_ref.range),
    None,
  ))
} else {
  let mut message = enhanced_resolution_error_message(error);
  // the diagnostic already shows the location, so this is redundant
  remove_imported_from(&mut message);
  Some(Self::from_missing_error_with_message(
    error_ref.specifier,
    Some(error_ref.range),
    message,
  ))
}

match unsafe_mut {
  Self::Pending {
    future,
    registration,
  } => {
    // Drop the registration without unpinning. This is safe as we don't move it.
    std::ptr::drop_in_place(registration);
    // Move the future data (it's Unpin and we're going to overwrite the other bits below, so this is safe)
    let f = std::ptr::read(future);
    // Overwrite the whole struct with Cancelable::Terminated to avoid double-drops for both future and registration
    std::ptr::write(unsafe_mut, Cancelable::Terminated);
    // We've liberated the future!
    Some(f)
  }
  Self::Terminated => None,
}

if DENO_SNAPSHOT_SET.load(Ordering::SeqCst) {
  let current = DENO_SNAPSHOT.load(Ordering::SeqCst);
  assert_eq!(
    current, snapshot,
    "V8 may only be initialized once in either snapshotting or non-snapshotting mode. Either snapshotting or non-snapshotting mode may be used in a single process, not both."
  );
  DENO_SNAPSHOT_SET.store(true, Ordering::SeqCst);
  DENO_SNAPSHOT.store(snapshot, Ordering::SeqCst);
}

if specifier.starts_with("jsr:") {
  let jsr_ref = JsrPackageReqReference::from_str(specifier).ok()?;
  // Use the @jsr/-scoped npm name so the dependency resolves on
  // `npm install`. The JSR scope/name pair is rewritten by
  // `jsr_name_to_npm`; see https://jsr.io/docs/npm-compatibility.
  let name = jsr_name_to_npm(&jsr_ref.req().name);
  let version = normalize_version(jsr_ref.req().version_req.version_text());
  return Some((name, version));
}

for (specifier, _) in root_names.iter().skip(1) {
  let (key, _) = compiler_options_resolver.entry_for_specifier(specifier);
  if key != first_key {
    anyhow::bail!(
      "Cannot generate declarations for files with different compiler option scopes.\n\
       '{}' uses scope '{}' but '{}' uses scope '{}'.\n\
       Separate these files into different invocations.",
      first_specifier,
      first_key,
      specifier,
      key,
    );
  }
}

if (result == Ok(1) || mode == napi_tsfn_abort)
      && tsfn
        .is_closing
        .compare_exchange(false, true, Ordering::SeqCst, Ordering::SeqCst)
        .is_ok()
    {
      tsfn.queue_cond.notify_all();
      let tsfnptr = SendPtr(tsfn);
      // drop must be queued in order to preserve ordering consistent
      // with Node.js and so that the finalizer runs on the main thread.
      tsfn.sender.spawn(move |_| {
        let tsfn = unsafe { Box::from_raw(tsfnptr.take() as *mut TsFn) };
        drop(tsfn);
      });
    }

if let Some(mut buffer) = inner
            .payload
            .as_ref()
            .expect("Field should not be polled after completion")
            .get_mut(&this.safety)
        {
            // check safety and poll read payload to buffer.
            buffer.poll_stream(cx)?;
        } else if !this.safety.is_clean() {
            // safety violation
            return Poll::Ready(Some(Err(Error::NotConsumed)));
        } else {
            return Poll::Pending;
        }

if self.child.wait()?.success() {
    Ok(())
} else {
    let err = self.stderr.read_to_end();
    // In the specific case where we haven't consumed the full data
    // from the child process, then closing stdout above results in
    // a pipe signal being thrown in most cases. But I don't think
    // there is any reliable and portable way of detecting it. Instead,
    // if we know we haven't hit EOF (so we anticipate a broken pipe
    // error) and if stderr otherwise doesn't have anything on it, then
    // we assume total success.
    if !self.eof && err.is_empty() {
        return Ok(());
    }
    Err(io::Error::from(err))
}

if self.whole_line {
    singlepat = format!(r"(?m:^)(?:{})(?m:$)", singlepat);
} else if self.word {
    // We make this option exclusive with whole_line because when
    // whole_line is enabled, all matches necessary fall on word
    // boundaries. So this extra goop is strictly redundant.
    singlepat = format!(r"(?<!\w)(?:{})(?!\w)", singlepat);
}

if is_multi_line {
    if bytes[range.end..].len() >= MAX_LOOK_AHEAD {
        bytes = &bytes[..range.end + MAX_LOOK_AHEAD];
    }
} else {
    // When searching a single line, we should remove the line terminator.
    // Otherwise, it's possible for the regex (via look-around) to observe
    // the line terminator and not match because of it.
    let mut m = Match::new(0, range.end);
    // No need to rember the line terminator as we aren't doing a replace
    // here.
    trim_line_terminator(searcher, bytes, &mut m);
    bytes = &bytes[..m.end()];
}

for p in patterns.iter() {
    let p = p.as_ref();
    if p.chars().any(regex_syntax::is_meta_character) {
        return false;
    }
    // Same deal as when fixed_strings is set above. If the pattern has
    // a line terminator anywhere, then we need to bail out and let
    // an error occur.
    if let Some(lineterm) = self.line_terminator {
        if has_line_terminator(lineterm, p) {
            return false;
        }
    }
}

while let Some(offset) = doc.find(&tag_prefix) {
    out.push_str(&doc[..offset]);

    let start = offset + tag_prefix.len();
    let Some(end) = doc[start..].find('}').map(|i| start + i) else {
        unreachable!(r"found {tag_prefix} without closing }}");
    };
    let name = &doc[start..end];
    replacement(name, &mut out);
    doc = &doc[end + 1..];
}

match self {
    Self::Downcast { actual, expected } => {
        writeln!(
            f,
            "Could not downcast to {expected:?}, need to downcast to {actual:?}"
        )
    }
    Self::UnknownArgument {} => {
        writeln!(
            f,
            "Unknown argument or group id.  Make sure you are using the argument id and not the short or long flags"
        )
    }
}

if let Ok((file_source, file_diagnostics)) = &r
          && let Some(incremental_cache) = &maybe_incremental_cache_
          && file_diagnostics.is_empty()
        {
          // update the incremental cache if there were no diagnostics
          incremental_cache.update_file(
            &file_path,
            // ensure the returned text is used here as it may have been modified via --fix
            file_source.text(),
          )
        }

if async_resource.is_none() {
  // If no resource provided, create a new empty object (matching Node.js)
  v8::Object::new(scope)
} else {
  // Node.js applies ToObject() coercion. If it fails (e.g. null/undefined),
  // propagate the error rather than silently substituting {}.
  let resource_local = async_resource.unwrap();
  match resource_local.to_object(scope) {
    Some(obj) => obj,
    None => {
      return napi_set_last_error(env, napi_object_expected);
    }
  }
}

if crt_fd >= 0 {
  self.base.set_fd(-1);
  // SAFETY: crt_fd is a valid CRT fd registered with the FdTable
  // by `open()`. `close_pipe` already closed the duplicated OS
  // handle this pipe owns; the original handle held by the CRT
  // fd is closed here, freeing both the OS handle and the CRT fd
  // slot.
  unsafe {
    libc::close(crt_fd);
  }
}
